use std::collections::HashMap;
use std::fmt;
use std::fs;
use std::num::ParseIntError;

#[derive(Debug)]
pub enum ConfigError {
    IoError(std::io::Error),
    MissingKey(String),
    InvalidFormat(String),
    InvalidValue { key: String, value: String },
    ParseError { key: String, source: ParseIntError },
}

impl fmt::Display for ConfigError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            ConfigError::IoError(e) => write!(f, "IO error: {}", e),
            ConfigError::MissingKey(k) => write!(f, "missing key: {}", k),
            ConfigError::InvalidFormat(line) => write!(f, "invalid format: {}", line),
            ConfigError::InvalidValue { key, value } => write!(f, "invalid value for {}: {}", key, value),
            ConfigError::ParseError { key, source } => write!(f, "parse error for {}: {}", key, source),
        }
    }
}

impl From<std::io::Error> for ConfigError {
    fn from(e: std::io::Error) -> Self {
        ConfigError::IoError(e)
    }
}

pub fn load_config(path: &str) -> Result<HashMap<String, String>, ConfigError> {
    let content = fs::read_to_string(path)?;
    let mut config = HashMap::new();

    for line in content.lines() {
        let line = line.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }
        let parts: Vec<&str> = line.splitn(2, '=').collect();
        if parts.len() != 2 {
            return Err(ConfigError::InvalidFormat(line.to_string()));
        }
        let key = parts[0].trim().to_string();
        let value = parts[1].trim().to_string();
        config.insert(key, value);
    }

    Ok(config)
}

pub fn get_int(config: &HashMap<String, String>, key: &str) -> Result<i64, ConfigError> {
    let value = config.get(key)
        .ok_or_else(|| ConfigError::MissingKey(key.to_string()))?;
    value.parse::<i64>()
        .map_err(|e| ConfigError::ParseError { key: key.to_string(), source: e })
}

pub fn get_bool(config: &HashMap<String, String>, key: &str) -> Result<bool, ConfigError> {
    let val = config.get(key)
        .ok_or_else(|| ConfigError::MissingKey(key.to_string()))?;
    match val.as_str() {
        "true" | "1" | "yes" => Ok(true),
        "false" | "0" | "no" => Ok(false),
        _ => Err(ConfigError::InvalidValue {
            key: key.to_string(),
            value: val.to_string(),
        }),
    }
}

